data: {"type":"response.output_item.done","item":{"type":"fabric_dataagent_preview_call_output","id":"fco_01cbd16b6f33c2780069cc4618d9808195bf8b2fb87a887274","agent_reference":{"type":"agent_reference","name":"MyAgent","version":"46"},"response_id":"resp_01cbd16b6f33c2780069cc4606ac9c819582a60e30c556532e","call_id":"call_5444fa1fff60405d839ba1a39164b3bb","output":"{\"documents\":[{\"id\":\"f66912c6-c8bf-4bc5-a24b-f863854175ed\",\"content\":\"Here are some of the most recent significant weather events in Texas:\\n\\n- **High Wind (Dec 30, 2007):** A peak gust of 71 mph was recorded at McDonald Observatory in the Davis Mountains. No reported injuries or property/ crop damages.\\n- **High Wind (Dec 27, 2007):** Gusts of around 60 mph broke windows in downtown El Paso and knocked down power poles elsewhere in the city.\\n- **Heavy Snow (Dec 27, 2007):** Four inches of snow were reported both fifteen miles south of Perryton and at Spearman in the Texas Panhandle.\\n- **Winter Weather Accident (Dec 27, 2007):** Snow and icy conditions led to a fatal rollover on U.S. Highway 287 near the Canadian River Bridge (one death, three injuries).\\n- **Tornadoes (Dec 27, 2007):** Tornado sightings near Slaton/Southland and north of Lubbock with no reported damage.\\n- **Strong Wind (Dec 27, 2007):** Strong winds in Lubbock caused a metal shed to collapse against a home, resulting in minor property damage (about $2,000).\\n\\nIf you need more details or information for a different time frame or location, just let me know!\\n\",\"filepath\":\"fabric://response\",\"title\":\"Fabric Response for: Show recent weather events in Texas.\",\"url\":\"https://msit.fabric.microsoft.com/groups/409e30ce-b2ad-4c80-a54d-d645227322e4/aiskills/98042b9e-11cb-422d-bd97-5873411aa7c8/stage/published/threads/thread_MuEWccMsL1Y7Q2gTKDe0QxyT/runs/run_fabBAstC7nn5xKJjrYqVXOeCuUl4/question/msg_Fl4HzBUTLhTtUNBsuWH0qxLR/source/foundry\",\"metadata\":\"{\\u0022source\\u0022:\\u0022azure_fabric\\u0022,\\u0022query\\u0022:\\u0022Show recent weather events in Texas.\\u0022,\\u0022data_agent_url\\u0022:\\u0022https://msit.fabric.microsoft.com/groups/409e30ce-b2ad-4c80-a54d-d645227322e4/aiskills/98042b9e-11cb-422d-bd97-5873411aa7c8/stage/published/threads/thread_MuEWccMsL1Y7Q2gTKDe0QxyT/runs/run_fabBAstC7nn5xKJjrYqVXOeCuUl4/question/msg_Fl4HzBUTLhTtUNBsuWH0qxLR/source/foundry\\u0022}\",\"score\":1,\"knowledgeSourceIndex\":0}]}","status":"completed"},"output_index":1,"sequence_number":5}

